"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[72951],{29930:(e,t,i)=>{i.r(t),i.d(t,{data:()=>r});const r={key:"v-2c6d6832",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/04.HtmlTextWriter%E7%9A%84%E4%B8%89%E4%B8%AA%E6%9C%80%E4%BD%B3%E6%8B%8D%E6%A1%A3.html",title:"自定义控件(四)-HtmlTextWriter的三个最佳拍档",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/04.HtmlTextWriter的三个最佳拍档.md"}},4875:(e,t,i)=>{i.r(t),i.d(t,{default:()=>A});const r=(0,i(57293).uE)('<h1 id="自定义控件-四-htmltextwriter的三个最佳拍档" tabindex="-1"><a class="header-anchor" href="#自定义控件-四-htmltextwriter的三个最佳拍档" aria-hidden="true">#</a> 自定义控件(四)-HtmlTextWriter的三个最佳拍档</h1><p>上篇文章深入的学习了HtmlTextWriter，这篇文章我来讲讲HtmlTextWriter的三个最佳拍档。HtmlTextWriterTag，HtmlTextWriterAttribute，HtmlTextWriterStyle.</p><p>1.HtmlTextWriterTag用来表示HTML标签,使用HtmlTextWriter与HtmlTextWriterTag我们可以很方便定义html，下面我们创建一个div</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>    StringWriter sw = new System.IO.StringWriter();\n    HtmlTextWriter writer = new HtmlTextWriter(sw);\n    writer.RenderBeginTag(HtmlTextWriterTag.Div);     //&lt;div&gt;\n    writer.RenderEndTag();                            //&lt;/div&gt;\n    pre1.InnerText = sw.ToString();\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853092.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>2.HtmlTextWriterAttribute用来表示HTML标签上的属性，需要先定义属性，再定义标签</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>        StringWriter sw = new System.IO.StringWriter();\n        HtmlTextWriter writer = new HtmlTextWriter(sw);\n        writer.AddAttribute(HtmlTextWriterAttribute.Width,&quot;100px&quot;);\n        writer.AddAttribute(HtmlTextWriterAttribute.Height, &quot;100px&quot;);\n        writer.RenderBeginTag(HtmlTextWriterTag.Img);     //&lt;div&gt;\n        writer.RenderEndTag();                            //&lt;/div&gt;\n        pre1.InnerText = sw.ToString();\n        Response.Write(sw.ToString());\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>也可以不使用HtmlTextWriterAttribute</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>    StringWriter sw = new System.IO.StringWriter();\n        HtmlTextWriter writer = new HtmlTextWriter(sw);\n        writer.AddAttribute(&quot;Width&quot;,&quot;100px&quot;);\n        writer.AddAttribute(&quot;Height&quot;, &quot;100px&quot;);\n        writer.RenderBeginTag(HtmlTextWriterTag.Img);     //&lt;div&gt;\n        writer.RenderEndTag();                            //&lt;/div&gt;\n        pre1.InnerText = sw.ToString();\n        Response.Write(sw.ToString());\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853093.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>3.HtmlTextWriterStyle用来表示样式：要先定义样式属性再定义标签</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>        StringWriter sw = new System.IO.StringWriter();\n        HtmlTextWriter writer = new HtmlTextWriter(sw);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.Width,&quot;100px&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.Height, &quot;100px&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.BackgroundColor, &quot;red&quot;);\n        writer.RenderBeginTag(HtmlTextWriterTag.Div);     //&lt;div&gt;\n        writer.RenderEndTag();                            //&lt;/div&gt;\n        pre1.InnerText = sw.ToString();\n        Response.Write(sw.ToString());\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>也可以不使用HtmlTextWriterStyle</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>        StringWriter sw = new System.IO.StringWriter();\n        HtmlTextWriter writer = new HtmlTextWriter(sw);\n        writer.AddStyleAttribute(&quot;width&quot;,&quot;100px&quot;);\n        writer.AddStyleAttribute(&quot;Height&quot;, &quot;100px&quot;);\n        writer.AddStyleAttribute(&quot;background-color&quot;, &quot;red&quot;);\n        writer.RenderBeginTag(HtmlTextWriterTag.Div);     //&lt;div&gt;\n        writer.RenderEndTag();                            //&lt;/div&gt;\n        pre1.InnerText = sw.ToString();\n        Response.Write(sw.ToString());\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853088.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>下面展示一个综合实例：</p><p>​</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>        StringWriter sw = new System.IO.StringWriter();\n        HtmlTextWriter writer = new HtmlTextWriter(sw);\n        //最外出DIV的样式属性\n        writer.AddStyleAttribute(HtmlTextWriterStyle.TextAlign,&quot;center&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.Width, &quot;194px&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.Height, &quot;194px&quot;);\n        writer.AddStyleAttribute(&quot;background&quot;, &quot;url(images/background.gif) no-repeat left&quot;);\n\n        //最外层的Div开始\n        writer.RenderBeginTag(HtmlTextWriterTag.Div);\n\n        //Img标签的属性和样式属性\n        writer.AddAttribute(HtmlTextWriterAttribute.Src,&quot;images/nature.jpg&quot;);\n        writer.AddAttribute(HtmlTextWriterAttribute.Width,&quot;160&quot;);\n        writer.AddAttribute(HtmlTextWriterAttribute.Height, &quot;160&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.BorderStyle, &quot;none&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.Padding, &quot;0px&quot;);\n        writer.AddStyleAttribute(HtmlTextWriterStyle.MarginTop, &quot;16px&quot;);\n\n        //生成Img标签\n        writer.RenderBeginTag(HtmlTextWriterTag.Img);\n        writer.RenderEndTag();\n\n        //结束最外层Div\n        writer.RenderEndTag();\n        pre1.InnerText = sw.ToString();\n        Response.Write(sw.ToString());\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210853119.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p>',28),n={},A=(0,i(63243).Z)(n,[["render",function(e,t){return r}]])},63243:(e,t)=>{t.Z=(e,t)=>{const i=e.__vccOpts||e;for(const[e,r]of t)i[e]=r;return i}}}]);